constructor(name, value) {
  const { escapeName } = this.constructor;
  const isStringValue = utils.isString(value);

  let headers = `Content-Disposition: form-data; name="${escapeName(name)}"${
    !isStringValue && value.name ? `; filename="${escapeName(value.name)}"` : ''
  }${CRLF}`;

  if (isStringValue) {
    value = textEncoder.encode(String(value).replace(/\r?\n|\r\n?/g, CRLF));
  } else {
    const safeType = String(value.type || 'application/octet-stream').replace(/[\r\n]/g, '');
    headers += `Content-Type: ${safeType}${CRLF}`;
  }

  this.headers = textEncoder.encode(headers + CRLF);

  this.contentLength = isStringValue ? value.byteLength : value.size;

  this.size = this.headers.byteLength + this.contentLength + CRLF_BYTES_COUNT;

  this.name = name;
  this.value = value;
}

async *encode() {
  yield this.headers;

  const { value } = this;

  if (utils.isTypedArray(value)) {
    yield value;
  } else {
    yield* readBlob(value);
  }

  yield CRLF_BYTES;
}

toISOString() {
  const Y = getNumberUnitFormat(this.$d.years, 'Y')
  const M = getNumberUnitFormat(this.$d.months, 'M')

  let days = +this.$d.days || 0
  if (this.$d.weeks) {
    days += this.$d.weeks * 7
  }

  const D = getNumberUnitFormat(days, 'D')
  const H = getNumberUnitFormat(this.$d.hours, 'H')
  const m = getNumberUnitFormat(this.$d.minutes, 'M')

  let seconds = this.$d.seconds || 0
  if (this.$d.milliseconds) {
    seconds += this.$d.milliseconds / 1000
    seconds = Math.round(seconds * 1000) / 1000
  }

  const S = getNumberUnitFormat(seconds, 'S')

  const negativeMode =
    Y.negative ||
    M.negative ||
    D.negative ||
    H.negative ||
    m.negative ||
    S.negative

  const T = H.format || m.format || S.format ? 'T' : ''
  const P = negativeMode ? '-' : ''

  const result = `${P}P${Y.format}${M.format}${D.format}${T}${H.format}${m.format}${S.format}`
  return result === 'P' || result === '-P' ? 'P0D' : result
}

compute() {
  const { maxRestSteps, maxIterations, restThreshold, timeStep, m, d, s, v } = this;
  const w0 = this.w0 = clamp(sqrt(s / m), minValue, K);
  const bouncedZeta = this.zeta = d / (2 * sqrt(s * m));
  // Calculate wd based on damping type
  if (bouncedZeta < 1) {
    // Underdamped
    this.wd = w0 * sqrt(1 - bouncedZeta * bouncedZeta);
    this.b = (bouncedZeta * w0 + -v) / this.wd;
  } else if (bouncedZeta === 1) {
    // Critically damped
    this.wd = 0;
    this.b = -v + w0;
  } else {
    // Overdamped
    this.wd = w0 * sqrt(bouncedZeta * bouncedZeta - 1);
    this.b = (bouncedZeta * w0 + -v) / this.wd;
  }

  let solverTime = 0;
  let restSteps = 0;
  let iterations = 0;
  while (restSteps <= maxRestSteps && iterations <= maxIterations) {
    if (abs(1 - this.solve(solverTime)) < restThreshold) {
      restSteps++;
    } else {
      restSteps = 0;
    }
    this.solverDuration = solverTime;
    solverTime += timeStep;
    iterations++;
  }
  this.settlingDuration = round(this.solverDuration * K, 0) * globals.timeScale;
}

export function clipPolygon(points, bounds, round) {
	let clippedPoints,
	i, j, k,
	a, b,
	len, edge, p;
	const edges = [1, 4, 2, 8];

	for (i = 0, len = points.length; i < len; i++) {
		points[i]._code = LineUtil._getBitCode(points[i], bounds);
	}

	// for each edge (left, bottom, right, top)
	for (k = 0; k < 4; k++) {
		edge = edges[k];
		clippedPoints = [];

		for (i = 0, len = points.length, j = len - 1; i < len; j = i++) {
			a = points[i];
			b = points[j];

			// if a is inside the clip window
			if (!(a._code & edge)) {
				// if b is outside the clip window (a->b goes out of screen)
				if (b._code & edge) {
					p = LineUtil._getEdgeIntersection(b, a, edge, bounds, round);
					p._code = LineUtil._getBitCode(p, bounds);
					clippedPoints.push(p);
				}
				clippedPoints.push(a);

			// else if b is inside the clip window (a->b enters the screen)
			} else if (!(b._code & edge)) {
				p = LineUtil._getEdgeIntersection(b, a, edge, bounds, round);
				p._code = LineUtil._getBitCode(p, bounds);
				clippedPoints.push(p);
			}
		}
		points = clippedPoints;
	}

	return points;
}

function compareAscending(value, other) {
  if (value !== other) {
    var valIsDefined = value !== undefined,
        valIsNull = value === null,
        valIsReflexive = value === value,
        valIsSymbol = isSymbol(value);

    var othIsDefined = other !== undefined,
        othIsNull = other === null,
        othIsReflexive = other === other,
        othIsSymbol = isSymbol(other);

    if ((!othIsNull && !othIsSymbol && !valIsSymbol && value > other) ||
        (valIsSymbol && othIsDefined && othIsReflexive && !othIsNull && !othIsSymbol) ||
        (valIsNull && othIsDefined && othIsReflexive) ||
        (!valIsDefined && othIsReflexive) ||
        !valIsReflexive) {
      return 1;
    }
    if ((!valIsNull && !valIsSymbol && !othIsSymbol && value < other) ||
        (othIsSymbol && valIsDefined && valIsReflexive && !valIsNull && !valIsSymbol) ||
        (othIsNull && valIsDefined && valIsReflexive) ||
        (!othIsDefined && valIsReflexive) ||
        !othIsReflexive) {
      return -1;
    }
  }
  return 0;
}

import { elementStyle } from '../../shared/utils.mjs';

export default function updateSize() {
  const swiper = this;
  let width;
  let height;
  const el = swiper.el;
  if (typeof swiper.params.width !== 'undefined' && swiper.params.width !== null) {
    width = swiper.params.width;
  } else {
    width = el.clientWidth;
  }
  if (typeof swiper.params.height !== 'undefined' && swiper.params.height !== null) {
    height = swiper.params.height;
  } else {
    height = el.clientHeight;
  }
  if ((width === 0 && swiper.isHorizontal()) || (height === 0 && swiper.isVertical())) {
    return;
  }

  // Subtract paddings
  width =
    width -
    parseInt(elementStyle(el, 'padding-left') || 0, 10) -
    parseInt(elementStyle(el, 'padding-right') || 0, 10);
  height =
    height -
    parseInt(elementStyle(el, 'padding-top') || 0, 10) -
    parseInt(elementStyle(el, 'padding-bottom') || 0, 10);

  if (Number.isNaN(width)) width = 0;
  if (Number.isNaN(height)) height = 0;

  Object.assign(swiper, {
    width,
    height,
    size: swiper.isHorizontal() ? width : height,
  });
}

function flattenDoc(doc) {
  if (!doc) {
    return "";
  }

  if (Array.isArray(doc)) {
    const res = [];
    for (const part of doc) {
      if (Array.isArray(part)) {
        res.push(...flattenDoc(part));
      } else {
        const flattened = flattenDoc(part);
        if (flattened !== "") {
          res.push(flattened);
        }
      }
    }

    return res;
  }

  if (doc.type === DOC_TYPE_IF_BREAK) {
    return {
      ...doc,
      breakContents: flattenDoc(doc.breakContents),
      flatContents: flattenDoc(doc.flatContents),
    };
  }

  if (doc.type === DOC_TYPE_GROUP) {
    return {
      ...doc,
      contents: flattenDoc(doc.contents),
      expandedStates: doc.expandedStates?.map(flattenDoc),
    };
  }

  if (doc.type === DOC_TYPE_FILL) {
    return { type: "fill", parts: doc.parts.map(flattenDoc) };
  }

  if (doc.contents) {
    return { ...doc, contents: flattenDoc(doc.contents) };
  }

  return doc;
}

const transformChunk = (_chunk, _callback) => {
  const chunkSize = Buffer.byteLength(_chunk);
  let chunkRemainder = null;
  let maxChunkSize = readableHighWaterMark;
  let bytesLeft;
  let passed = 0;

  if (maxRate) {
    const now = Date.now();

    if (!internals.ts || (passed = now - internals.ts) >= timeWindow) {
      internals.ts = now;
      bytesLeft = bytesThreshold - internals.bytes;
      internals.bytes = bytesLeft < 0 ? -bytesLeft : 0;
      passed = 0;
    }

    bytesLeft = bytesThreshold - internals.bytes;
  }

  if (maxRate) {
    if (bytesLeft <= 0) {
      // next time window
      return setTimeout(() => {
        _callback(null, _chunk);
      }, timeWindow - passed);
    }

    if (bytesLeft < maxChunkSize) {
      maxChunkSize = bytesLeft;
    }
  }

  if (maxChunkSize && chunkSize > maxChunkSize && chunkSize - maxChunkSize > minChunkSize) {
    chunkRemainder = _chunk.subarray(maxChunkSize);
    _chunk = _chunk.subarray(0, maxChunkSize);
  }

  pushChunk(
    _chunk,
    chunkRemainder
      ? () => {
          process.nextTick(_callback, null, chunkRemainder);
        }
      : _callback
  );
};

function formDataToJSON(formData) {
  function buildPath(path, value, target, index) {
    let name = path[index++];

    if (name === '__proto__') return true;

    const isNumericKey = Number.isFinite(+name);
    const isLast = index >= path.length;
    name = !name && utils.isArray(target) ? target.length : name;

    if (isLast) {
      if (utils.hasOwnProp(target, name)) {
        target[name] = utils.isArray(target[name])
          ? target[name].concat(value)
          : [target[name], value];
      } else {
        target[name] = value;
      }

      return !isNumericKey;
    }

    if (!utils.hasOwnProp(target, name) || !utils.isObject(target[name])) {
      target[name] = [];
    }

    const result = buildPath(path, value, target[name], index);

    if (result && utils.isArray(target[name])) {
      target[name] = arrayToObject(target[name]);
    }

    return !isNumericKey;
  }

  if (utils.isFormData(formData) && utils.isFunction(formData.entries)) {
    const obj = {};

    utils.forEachEntry(formData, (name, value) => {
      buildPath(parsePropPath(name), value, obj, 0);
    });

    return obj;
  }

  return null;
}

export default function fromDataURI(uri, asBlob, options) {
  const _Blob = (options && options.Blob) || platform.classes.Blob;
  const protocol = parseProtocol(uri);

  if (asBlob === undefined && _Blob) {
    asBlob = true;
  }

  if (protocol === 'data') {
    uri = protocol.length ? uri.slice(protocol.length + 1) : uri;

    const match = DATA_URL_PATTERN.exec(uri);

    if (!match) {
      throw new AxiosError('Invalid URL', AxiosError.ERR_INVALID_URL);
    }

    const type = match[1];
    const params = match[2];
    const encoding = match[3] ? 'base64' : 'utf8';
    const body = match[4];

    // RFC 2397 section 3: default mediatype is text/plain;charset=US-ASCII
    // Bare `data:,` leaves mime undefined; Blob normalises that to "" per spec.
    let mime;
    if (type) {
      mime = params ? type + params : type;
    } else if (params) {
      mime = 'text/plain' + params;
    }

    const buffer = Buffer.from(decodeURIComponent(body), encoding);

    if (asBlob) {
      if (!_Blob) {
        throw new AxiosError('Blob is not supported', AxiosError.ERR_NOT_SUPPORT);
      }

      return new _Blob([buffer], { type: mime });
    }

    return buffer;
  }

  throw new AxiosError('Unsupported protocol ' + protocol, AxiosError.ERR_NOT_SUPPORT);
}

export const trackStream = (stream, chunkSize, onProgress, onFinish) => {
  const iterator = readBytes(stream, chunkSize);

  let bytes = 0;
  let done;
  let _onFinish = (e) => {
    if (!done) {
      done = true;
      onFinish && onFinish(e);
    }
  };

  return new ReadableStream(
    {
      async pull(controller) {
        try {
          const { done, value } = await iterator.next();

          if (done) {
            _onFinish();
            controller.close();
            return;
          }

          let len = value.byteLength;
          if (onProgress) {
            let loadedBytes = (bytes += len);
            onProgress(loadedBytes);
          }
          controller.enqueue(new Uint8Array(value));
        } catch (err) {
          _onFinish(err);
          throw err;
        }
      },
      cancel(reason) {
        _onFinish(reason);
        return iterator.return();
      },
    },
    {
      highWaterMark: 2,
    }
  );
};

export default function autoInject(tasks, callback) {
    var newTasks = {};

    Object.keys(tasks).forEach(key => {
        var taskFn = tasks[key]
        var params;
        var fnIsAsync = isAsync(taskFn);
        var hasNoDeps =
            (!fnIsAsync && taskFn.length === 1) ||
            (fnIsAsync && taskFn.length === 0);

        if (Array.isArray(taskFn)) {
            params = [...taskFn];
            taskFn = params.pop();

            newTasks[key] = params.concat(params.length > 0 ? newTask : taskFn);
        } else if (hasNoDeps) {
            // no dependencies, use the function as-is
            newTasks[key] = taskFn;
        } else {
            params = parseParams(taskFn);
            if ((taskFn.length === 0 && !fnIsAsync) && params.length === 0) {
                throw new Error("autoInject task functions require explicit parameters.");
            }

            // remove callback param
            if (!fnIsAsync) params.pop();

            newTasks[key] = params.concat(newTask);
        }

        function newTask(results, taskCb) {
            var newArgs = params.map(name => results[name])
            newArgs.push(taskCb);
            wrapAsync(taskFn)(...newArgs);
        }
    });

    return auto(newTasks, callback);
}

export default function retry(opts, task, callback) {
    var options = {
        times: DEFAULT_TIMES,
        intervalFunc: constant(DEFAULT_INTERVAL)
    };

    if (arguments.length < 3 && typeof opts === 'function') {
        callback = task || promiseCallback();
        task = opts;
    } else {
        parseTimes(options, opts);
        callback = callback || promiseCallback();
    }

    if (typeof task !== 'function') {
        throw new Error("Invalid arguments for async.retry");
    }

    var _task = wrapAsync(task);

    var attempt = 1;
    function retryAttempt() {
        _task((err, ...args) => {
            if (err === false) return
            if (err && attempt++ < options.times &&
                (typeof options.errorFilter != 'function' ||
                    options.errorFilter(err))) {
                setTimeout(retryAttempt, options.intervalFunc(attempt - 1));
            } else {
                callback(err, ...args);
            }
        });
    }

    retryAttempt();
    return callback[PROMISE_SYMBOL]
}

function validateExpression(node) {
	if (node.body.type === "BlockStatement") {
		return;
	}

	const arrowToken = sourceCode.getTokenBefore(
		node.body,
		isNotOpeningParenToken,
	);
	const firstTokenOfBody = sourceCode.getTokenAfter(arrowToken);

	if (
		arrowToken.loc.end.line === firstTokenOfBody.loc.start.line &&
		option === "below"
	) {
		context.report({
			node: firstTokenOfBody,
			messageId: "expected",
			fix: fixer =>
				fixer.insertTextBefore(firstTokenOfBody, "\n"),
		});
	} else if (
		arrowToken.loc.end.line !== firstTokenOfBody.loc.start.line &&
		option === "beside"
	) {
		context.report({
			node: firstTokenOfBody,
			messageId: "unexpected",
			fix(fixer) {
				if (
					sourceCode.getFirstTokenBetween(
						arrowToken,
						firstTokenOfBody,
						{
							includeComments: true,
							filter: isCommentToken,
						},
					)
				) {
					return null;
				}

				return fixer.replaceTextRange(
					[arrowToken.range[1], firstTokenOfBody.range[0]],
					" ",
				);
			},
		});
	}
}

function checkNodeIndent(node, neededIndent) {
	const actualIndent = getNodeIndent(node, false);

	if (
		node.type !== "ArrayExpression" &&
		node.type !== "ObjectExpression" &&
		(actualIndent.goodChar !== neededIndent ||
			actualIndent.badChar !== 0) &&
		isNodeFirstInLine(node)
	) {
		report(
			node,
			neededIndent,
			actualIndent.space,
			actualIndent.tab,
		);
	}

	if (node.type === "IfStatement" && node.alternate) {
		const elseToken = sourceCode.getTokenBefore(node.alternate);

		checkNodeIndent(elseToken, neededIndent);

		if (!isNodeFirstInLine(node.alternate)) {
			checkNodeIndent(node.alternate, neededIndent);
		}
	}

	if (node.type === "TryStatement" && node.handler) {
		const catchToken = sourceCode.getFirstToken(node.handler);

		checkNodeIndent(catchToken, neededIndent);
	}

	if (node.type === "TryStatement" && node.finalizer) {
		const finallyToken = sourceCode.getTokenBefore(node.finalizer);

		checkNodeIndent(finallyToken, neededIndent);
	}

	if (node.type === "DoWhileStatement") {
		const whileToken = sourceCode.getTokenAfter(node.body);

		checkNodeIndent(whileToken, neededIndent);
	}
}

function isImportExportCanBeMerged(node1, node2) {
	const importExportType1 = getImportExportType(node1);
	const importExportType2 = getImportExportType(node2);

	if (
		(node1.importKind === "type" || node1.exportKind === "type") &&
		(node2.importKind === "type" || node2.exportKind === "type")
	) {
		const isDefault1 = importExportType1 === "ImportDefaultSpecifier";
		const isDefault2 = importExportType2 === "ImportDefaultSpecifier";
		const isNamed1 = isImportExportSpecifier(importExportType1, "named");
		const isNamed2 = isImportExportSpecifier(importExportType2, "named");

		if ((isDefault1 && isNamed2) || (isDefault2 && isNamed1)) {
			return false;
		}
	}

	if (
		(importExportType1 === "ExportAll" &&
			importExportType2 !== "ExportAll" &&
			importExportType2 !== "SideEffectImport") ||
		(importExportType1 !== "ExportAll" &&
			importExportType1 !== "SideEffectImport" &&
			importExportType2 === "ExportAll")
	) {
		return false;
	}
	if (
		(isImportExportSpecifier(importExportType1, "namespace") &&
			isImportExportSpecifier(importExportType2, "named")) ||
		(isImportExportSpecifier(importExportType2, "namespace") &&
			isImportExportSpecifier(importExportType1, "named"))
	) {
		return false;
	}
	return true;
}

function ruleApplies(node) {
	if (node.type === "JSXElement" || node.type === "JSXFragment") {
		const isSingleLine = node.loc.start.line === node.loc.end.line;

		switch (IGNORE_JSX) {
			// Exclude this JSX element from linting
			case "all":
				return false;

			// Exclude this JSX element if it is multi-line element
			case "multi-line":
				return isSingleLine;

			// Exclude this JSX element if it is single-line element
			case "single-line":
				return !isSingleLine;

			// Nothing special to be done for JSX elements
			case "none":
				break;

			// no default
		}
	}

	if (
		node.type === "SequenceExpression" &&
		IGNORE_SEQUENCE_EXPRESSIONS
	) {
		return false;
	}

	if (
		isImmediateFunctionPrototypeMethodCall(node) &&
		IGNORE_FUNCTION_PROTOTYPE_METHODS
	) {
		return false;
	}

	return (
		ALL_NODES ||
		node.type === "FunctionExpression" ||
		node.type === "ArrowFunctionExpression"
	);
}

function checkForLoops(node) {
	const loopNode = getContainingLoopNode(node);

	if (!loopNode) {
		return;
	}

	const references = sourceCode.getScope(node).through;

	// Check if the function is not asynchronous or a generator function
	if (!(node.async || node.generator)) {
		if (isIIFE(node)) {
			const isFunctionExpression =
				node.type === "FunctionExpression";

			// Check if the function is referenced elsewhere in the code
			const isFunctionReferenced =
				isFunctionExpression && node.id
					? references.some(
							r => r.identifier.name === node.id.name,
						)
					: false;

			if (!isFunctionReferenced) {
				SKIPPED_IIFE_NODES.add(node);
				return;
			}
		}
	}

	const unsafeRefs = [
		...new Set(
			references
				.filter(r => r.resolved && !isSafe(loopNode, r))
				.map(r => r.identifier.name),
		),
	];

	if (unsafeRefs.length > 0) {
		context.report({
			node,
			messageId: "unsafeRefs",
			data: { varNames: `'${unsafeRefs.join("', '")}'` },
		});
	}
}

function performCheck(leftNode, rightNode, reportNode) {
	if (
		rightNode.type !== "MemberExpression" ||
		rightNode.object.type === "Super" ||
		rightNode.property.type === "PrivateIdentifier"
	) {
		return;
	}

	if (isArrayIndexAccess(rightNode)) {
		if (shouldCheck(reportNode.type, "array")) {
			report(reportNode, "array", null);
		}
		return;
	}

	const fix = shouldFix(reportNode)
		? fixer => fixIntoObjectDestructuring(fixer, reportNode)
		: null;

	if (
		shouldCheck(reportNode.type, "object") &&
		enforceForRenamedProperties
	) {
		report(reportNode, "object", fix);
		return;
	}

	if (shouldCheck(reportNode.type, "object")) {
		const property = rightNode.property;

		if (
			(property.type === "Literal" &&
				leftNode.name === property.value) ||
			(property.type === "Identifier" &&
				leftNode.name === property.name &&
				!rightNode.computed)
		) {
			report(reportNode, "object", fix);
		}
	}
}

function suggestIfPossible(groupStart, pattern, rawText, regexNode) {
	switch (regexNode.type) {
		case "Literal":
			if (typeof regexNode.value === "string" && rawText.includes("\\")) {
				return null;
			}
			break;
		case "TemplateLiteral":
			if (
				regexNode.expressions.length ||
				rawText.slice(1, -1) !== pattern
			) {
				return null;
			}
			break;
		default:
			return null;
	}

	const start = regexNode.range[0] + groupStart + 2;

	return [
		{
			fix(fixer) {
				const existingTemps = pattern.match(/temp\d+/gu) || [];
				const highestTempCount = existingTemps.reduce(
					(previous, next) =>
						Math.max(previous, Number(next.slice("temp".length))),
					0,
				);

				return fixer.insertTextBeforeRange(
					[start, start],
					`?<temp${highestTempCount + 1}>`,
				);
			},
			messageId: "addGroupName",
		},
		{
			fix(fixer) {
				return fixer.insertTextBeforeRange([start, start], "?:");
			},
			messageId: "addNonCapture",
		},
	];
}

function check(semiToken, expected) {
	const prevToken = sourceCode.getTokenBefore(semiToken);
	const nextToken = sourceCode.getTokenAfter(semiToken);
	const prevIsSameLine =
		!prevToken || astUtils.isTokenOnSameLine(prevToken, semiToken);
	const nextIsSameLine =
		!nextToken || astUtils.isTokenOnSameLine(semiToken, nextToken);

	if (
		(expected === "last" && !prevIsSameLine) ||
		(expected === "first" && !nextIsSameLine)
	) {
		context.report({
			loc: semiToken.loc,
			messageId: "expectedSemiColon",
			data: {
				pos:
					expected === "last"
						? "the end of the previous line"
						: "the beginning of the next line",
			},
			fix(fixer) {
				if (
